    // Copy data without advancing read pointer using copy()
    std::vector<uint8_t> peeked_data(peek_size);
    adaptor.copy(peeked_data.data(), peek_size);

    // Consume the data by reading it using read()
    adaptor.read(peeked_data.data(), peek_size);

    return peeked_data;
}
