#include <string>

struct MeasurementData {
    uint32_t sensor_id;
    std::vector<float> temperatures;
    double pressure;

    void serialise(auto& adaptor) const {
        // Write sensor_id directly
        adaptor(sensor_id);

        // Convert and write each temperature with runtime endianness conversion
        for (const auto& temp : temperatures) {
            float converted = hexi::endian::conditional_reverse(
                temp, 
                std::endian::native, 
                std::endian::little
            );
            adaptor.write(&converted, sizeof(converted));
        }

        // Convert and write pressure with runtime endianness conversion
        double converted_pressure = hexi::endian::conditional_reverse(
            pressure, 
            std::endian::native, 
            std::endian::little
        );
        adaptor.write(&converted_pressure, sizeof(converted_pressure));
    }

    void deserialise(auto& adaptor) {
        // Read sensor_id directly
        adaptor(sensor_id);

        // Read temperatures count (assuming it was written as uint32_t)
        uint32_t count;
        adaptor(count);

        // Read each temperature and convert from little-endian to native
        temperatures.resize(count);
        for (auto& temp : temperatures) {
            adaptor(temp);
            hexi::endian::little_to_native_inplace(temp);
        }

        // Read pressure and convert from little-endian to native
        adaptor(pressure);
        hexi::endian::little_to_native_inplace(pressure);
    }
};

std::vector<uint8_t> serialize_measurement_data(const MeasurementData& data) {
    // Create a dynamic buffer to hold the serialized data
    hexi::dynamic_buffer<1024> buffer;

    // Create a stream with little-endian configuration
    hexi::stream<decltype(buffer), hexi::allow_throw_t, std::endian::little> stream(buffer);

    // Use the stream's serialise method to serialize the entire structure
    stream.serialise(data);

    // Return the serialized data as vector<uint8_t>
    return std::vector<uint8_t>(buffer.data(), buffer.data() + buffer.size());
}

MeasurementData deserialize_measurement_data(const std::span<const uint8_t> buffer) {
    // Create a buffer adaptor for the input span
    hexi::buffer_adaptor<std::span<const uint8_t>> adaptor(buffer);

    // Create a stream with little-endian configuration
    hexi::stream<decltype(adaptor), hexi::allow_throw_t, std::endian::little> stream(adaptor);

    // Create MeasurementData object and deserialize into it
    MeasurementData data;
    stream.deserialise(data);

    return data;
}

struct SensorInfo {
    uint32_t sensor_id;
    std::string_view sensor_name;
};

SensorInfo extract_sensor_info(const std::span<const uint8_t> buffer) {
    // Create a buffer adaptor for the input span
    hexi::buffer_adaptor<std::span<const uint8_t>> adaptor(buffer);

    // Create a stream with little-endian configuration
    hexi::stream<decltype(adaptor), hexi::allow_throw_t, std::endian::little> stream(adaptor);

    SensorInfo info;

    // Use view to extract null-terminated sensor name string
    info.sensor_name = stream.view();

    // Use enforce_read_bounds to check if there's enough data for sensor_id
    stream.enforce_read_bounds(sizeof(uint32_t));

